package com.secman.controller

import com.secman.dto.AffectedAssetsByCveDto
import com.secman.dto.AssetsByProductDto
import com.secman.dto.AvailableDomainsDto
import com.secman.dto.MostCommonVulnerabilityDto
import com.secman.dto.MostVulnerableProductDto
import com.secman.dto.VulnerabilityAgeTrendDto
import com.secman.dto.VulnerabilityStatisticsCacheStatusDto
import com.secman.service.VulnerabilityAgeSnapshotService
import com.secman.service.VulnerabilityStatisticsCacheService
import com.secman.service.VulnerabilityStatisticsService
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.MediaType
import io.micronaut.http.annotation.Body
import io.micronaut.http.annotation.Controller
import io.micronaut.http.annotation.Get
import io.micronaut.http.annotation.Post
import io.micronaut.http.annotation.Produces
import io.micronaut.http.annotation.QueryValue
import io.micronaut.security.annotation.Secured
import io.micronaut.security.authentication.Authentication
import io.micronaut.security.rules.SecurityRule
import org.slf4j.LoggerFactory

/**
 * REST API controller for vulnerability statistics
 *
 * Provides endpoints for aggregated vulnerability analytics:
 * - Most common vulnerabilities
 * - Severity distribution
 * - Top assets by vulnerability count
 * - Vulnerabilities by asset type
 * - Temporal trends
 *
 * Access Control: All endpoints require authentication (ADMIN or VULN role)
 * Statistics are filtered by workgroup for non-ADMIN users
 *
 * Feature: 036-vuln-stats-lense
 * Task: T005
 * Spec reference: spec.md Section "API Endpoints"
 * Contract: contracts/vulnerability-statistics-api.yaml
 */
@Controller("/api/vulnerability-statistics")
@Secured(SecurityRule.IS_AUTHENTICATED)
class VulnerabilityStatisticsController(
    private val vulnerabilityStatisticsService: VulnerabilityStatisticsService,
    private val vulnerabilityAgeSnapshotService: VulnerabilityAgeSnapshotService,
    private val vulnerabilityStatisticsCacheService: VulnerabilityStatisticsCacheService
) {
    private val logger = LoggerFactory.getLogger(VulnerabilityStatisticsController::class.java)

    /**
     * GET /api/vulnerability-statistics/available-domains
     *
     * Returns list of unique AD domains from assets the user has access to.
     * Used to populate the domain selector dropdown.
     *
     * Feature: 059-vuln-stats-domain-filter
     * Task: T003
     * Spec reference: spec.md FR-002
     * Contract: contracts/domain-filter-api.yaml /available-domains
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @return HTTP 200 with list of available domains, or HTTP 500 on error
     */
    @Get("/available-domains")
    @Produces(MediaType.APPLICATION_JSON)
    fun getAvailableDomains(authentication: Authentication): HttpResponse<AvailableDomainsDto> {
        return try {
            val result = vulnerabilityStatisticsService.getAvailableDomains(authentication)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching available domains", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/cache-status
     *
     * Returns whether the statistics cache is active and when it was last refreshed.
     * Used by the frontend to show a "Cached data" indicator.
     */
    @Get("/cache-status")
    @Produces(MediaType.APPLICATION_JSON)
    fun getCacheStatus(): HttpResponse<VulnerabilityStatisticsCacheStatusDto> {
        return try {
            val status = VulnerabilityStatisticsCacheStatusDto(
                cacheEnabled = vulnerabilityStatisticsCacheService.isCacheEnabled(),
                lastRefreshedAt = vulnerabilityStatisticsCacheService.getLastRefreshedAt()
            )
            HttpResponse.ok(status)
        } catch (e: Exception) {
            logger.error("Error fetching cache status", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/most-common
     *
     * Returns top 10 most frequently occurring vulnerabilities across accessible assets.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense, 059-vuln-stats-domain-filter
     * Task: T014 [US1], T007 (domain filter)
     * Spec reference: spec.md FR-001, FR-002
     * User Story: US1 - View Most Common Vulnerabilities (P1)
     * Contract: contracts/domain-filter-api.yaml /most-common
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @param domain Optional AD domain filter (case-insensitive). If omitted, returns data for all accessible domains.
     * @return HTTP 200 with list of most common vulnerabilities, or HTTP 500 on error
     */
    @Get("/most-common")
    @Produces(MediaType.APPLICATION_JSON)
    fun getMostCommonVulnerabilities(
        authentication: Authentication,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<List<MostCommonVulnerabilityDto>> {
        return try {
            val result = vulnerabilityStatisticsService.getMostCommonVulnerabilities(authentication, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching most common vulnerabilities", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/most-vulnerable-products
     *
     * Returns top 10 products ranked by distinct vulnerability count across accessible assets.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense, 059-vuln-stats-domain-filter
     * Task: T007 (domain filter)
     * Contract: contracts/domain-filter-api.yaml /most-vulnerable-products
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @param domain Optional AD domain filter (case-insensitive). If omitted, returns data for all accessible domains.
     * @return HTTP 200 with list of most vulnerable products, or HTTP 500 on error
     */
    @Get("/most-vulnerable-products")
    @Produces(MediaType.APPLICATION_JSON)
    fun getMostVulnerableProducts(
        authentication: Authentication,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<List<MostVulnerableProductDto>> {
        return try {
            val result = vulnerabilityStatisticsService.getMostVulnerableProducts(authentication, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching most vulnerable products", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/severity-distribution
     *
     * Returns vulnerability counts grouped by CVSS severity level (CRITICAL, HIGH, MEDIUM, LOW, UNKNOWN).
     * Includes computed percentage properties for visualization in pie charts.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense, 059-vuln-stats-domain-filter
     * Task: T024 [US2], T007 (domain filter)
     * Spec reference: spec.md FR-003, FR-004
     * User Story: US2 - View Severity Distribution (P2)
     * Contract: contracts/domain-filter-api.yaml /severity-distribution
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @param domain Optional AD domain filter (case-insensitive). If omitted, returns data for all accessible domains.
     * @return HTTP 200 with severity distribution DTO, or HTTP 500 on error
     */
    @Get("/severity-distribution")
    @Produces(MediaType.APPLICATION_JSON)
    fun getSeverityDistribution(
        authentication: Authentication,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<com.secman.dto.SeverityDistributionDto> {
        return try {
            val result = vulnerabilityStatisticsService.getSeverityDistribution(authentication, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching severity distribution", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/top-assets
     *
     * Returns top 10 assets ranked by total vulnerability count with severity breakdowns.
     * Useful for identifying which assets require the most urgent remediation attention.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense, 059-vuln-stats-domain-filter
     * Task: T034 [US3]
     * Spec reference: spec.md FR-005, FR-006
     * User Story: US3 - View Asset Vulnerability Statistics (P3)
     * Contract: contracts/vulnerability-statistics-api.yaml /top-assets
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @param domain Optional AD domain filter (case-insensitive). If omitted, returns data for all accessible domains.
     * @return HTTP 200 with list of top assets, or HTTP 500 on error
     */
    @Get("/top-assets")
    @Produces(MediaType.APPLICATION_JSON)
    fun getTopAssetsByVulnerabilities(
        authentication: Authentication,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<List<com.secman.dto.TopAssetByVulnerabilitiesDto>> {
        return try {
            val result = vulnerabilityStatisticsService.getTopAssetsByVulnerabilities(authentication, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching top assets by vulnerabilities", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/by-asset-type
     *
     * Returns vulnerability statistics grouped by asset type (Server, Workstation, Network Device, etc.).
     * Includes severity breakdowns and average vulnerabilities per asset for each type.
     * Useful for identifying systemic vulnerability patterns across infrastructure categories.
     * Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense
     * Task: T038 [US3]
     * Spec reference: spec.md FR-007, FR-008
     * User Story: US3 - View Asset Vulnerability Statistics (P3)
     * Contract: contracts/vulnerability-statistics-api.yaml /by-asset-type
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @return HTTP 200 with list of asset type statistics, or HTTP 500 on error
     */
    @Get("/by-asset-type")
    @Produces(MediaType.APPLICATION_JSON)
    fun getVulnerabilitiesByAssetType(authentication: Authentication): HttpResponse<List<com.secman.dto.VulnerabilityByAssetTypeDto>> {
        return try {
            val result = vulnerabilityStatisticsService.getVulnerabilitiesByAssetType(authentication)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching vulnerabilities by asset type", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/temporal-trends
     *
     * Returns time-series vulnerability data showing daily counts over specified period (30, 60, or 90 days).
     * Includes severity breakdowns for trend visualization in line charts.
     * Respects workgroup-based access control.
     *
     * Feature: 036-vuln-stats-lense
     * Task: T050 [US4]
     * Spec reference: spec.md FR-009, FR-010, FR-011
     * User Story: US4 - View Temporal Trends (P4)
     * Contract: contracts/vulnerability-statistics-api.yaml /temporal-trends
     *
     * @param authentication Current user authentication context (injected by Micronaut Security)
     * @param days Number of days to analyze (must be 30, 60, or 90)
     * @return HTTP 200 with temporal trends DTO, HTTP 400 for invalid days parameter, or HTTP 500 on error
     */
    @Get("/temporal-trends")
    @Produces(MediaType.APPLICATION_JSON)
    fun getTemporalTrends(
        authentication: Authentication,
        @QueryValue(defaultValue = "30") days: Int
    ): HttpResponse<*> {
        return try {
            // Validate days parameter
            if (days !in listOf(30, 60, 90)) {
                return HttpResponse.status<String>(HttpStatus.BAD_REQUEST)
                    .body("Days parameter must be 30, 60, or 90")
            }

            val result = vulnerabilityStatisticsService.getTemporalTrends(authentication, days)
            HttpResponse.ok(result)
        } catch (e: IllegalArgumentException) {
            HttpResponse.status<String>(HttpStatus.BAD_REQUEST).body("Invalid request parameters")
        } catch (e: Exception) {
            logger.error("Error fetching temporal trends", e)
            HttpResponse.serverError<String>()
        }
    }

    /**
     * GET /api/vulnerability-statistics/affected-assets/{cveId}
     *
     * Returns assets affected by a specific CVE within user's access scope.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Used in CVE drilldown modal to show which systems are affected.
     *
     * @param authentication Current user authentication context
     * @param cveId The CVE identifier (e.g., "CVE-2024-12345")
     * @param domain Optional AD domain filter (case-insensitive)
     * @return HTTP 200 with list of affected assets (max 100), or HTTP 500 on error
     */
    @Get("/affected-assets/{cveId}")
    @Produces(MediaType.APPLICATION_JSON)
    fun getAffectedAssetsByCve(
        authentication: Authentication,
        cveId: String,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<AffectedAssetsByCveDto> {
        return try {
            val result = vulnerabilityStatisticsService.getAffectedAssetsByCve(authentication, cveId, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching affected assets for CVE: $cveId", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/assets-by-product/{product}
     *
     * Returns assets that have a specific product installed within user's access scope.
     * Optionally filter by AD domain. Respects workgroup-based access control.
     *
     * Used in product drilldown modal to show which systems have the product installed.
     *
     * @param authentication Current user authentication context
     * @param product The product name to search for
     * @param domain Optional AD domain filter (case-insensitive)
     * @return HTTP 200 with list of assets (max 100), or HTTP 500 on error
     */
    @Get("/assets-by-product/{product}")
    @Produces(MediaType.APPLICATION_JSON)
    fun getAssetsByProduct(
        authentication: Authentication,
        product: String,
        @QueryValue domain: String?,
        @QueryValue awsHosted: Boolean?
    ): HttpResponse<AssetsByProductDto> {
        return try {
            val result = vulnerabilityStatisticsService.getAssetsByProduct(authentication, product, domain, awsHosted)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching assets for product: $product", e)
            HttpResponse.serverError()
        }
    }

    /**
     * POST /api/vulnerability-statistics/age-snapshot
     *
     * Triggers capture of a vulnerability age snapshot for the current day.
     * Feature: vulnerability-age-snapshot
     */
    @Post("/age-snapshot")
    @Secured("ADMIN", "VULN")
    @Produces(MediaType.APPLICATION_JSON)
    fun captureAgeSnapshot(
        @QueryValue(defaultValue = "30") thresholdDays: Int
    ): HttpResponse<Map<String, String>> {
        return try {
            vulnerabilityAgeSnapshotService.captureSnapshot(thresholdDays, "API")
            HttpResponse.ok(mapOf("status" to "ok", "message" to "Snapshot captured"))
        } catch (e: Exception) {
            logger.error("Error capturing vulnerability age snapshot", e)
            HttpResponse.serverError()
        }
    }

    /**
     * GET /api/vulnerability-statistics/age-snapshot-trend
     *
     * Returns vulnerability age snapshot trend data.
     * Feature: vulnerability-age-snapshot
     */
    @Get("/age-snapshot-trend")
    @Produces(MediaType.APPLICATION_JSON)
    fun getAgeSnapshotTrend(
        @QueryValue(defaultValue = "90") days: Int,
        @QueryValue(defaultValue = "30") thresholdDays: Int
    ): HttpResponse<VulnerabilityAgeTrendDto> {
        return try {
            val result = vulnerabilityAgeSnapshotService.getSnapshotTrend(days, thresholdDays)
            HttpResponse.ok(result)
        } catch (e: Exception) {
            logger.error("Error fetching vulnerability age snapshot trend", e)
            HttpResponse.serverError()
        }
    }

    /**
     * POST /api/vulnerability-statistics/age-snapshot-from-data
     *
     * Captures a vulnerability age snapshot from pre-computed data.
     * Used by CLI to save snapshot without re-querying the database.
     */
    @Post("/age-snapshot-from-data")
    @Secured("ADMIN", "VULN")
    @Produces(MediaType.APPLICATION_JSON)
    fun captureAgeSnapshotFromData(
        @Body request: AgeSnapshotFromDataRequest
    ): HttpResponse<Map<String, String>> {
        return try {
            vulnerabilityAgeSnapshotService.captureSnapshotFromData(
                totalServers = request.totalServers,
                serversWithOverdue = request.serversWithOverdue,
                thresholdDays = request.thresholdDays,
                source = request.source
            )
            HttpResponse.ok(mapOf("status" to "ok", "message" to "Snapshot captured from data"))
        } catch (e: Exception) {
            logger.error("Error capturing vulnerability age snapshot from data", e)
            HttpResponse.serverError()
        }
    }
}

@io.micronaut.serde.annotation.Serdeable
data class AgeSnapshotFromDataRequest(
    val totalServers: Int,
    val serversWithOverdue: Int,
    val thresholdDays: Int = 30,
    val source: String = "CLI"
)

package com.secman.service

import com.fasterxml.jackson.databind.ObjectMapper
import com.fasterxml.jackson.core.type.TypeReference
import com.secman.repository.ExceptionMatchSql
import com.secman.repository.VulnerabilityRepository
import io.micronaut.security.authentication.Authentication
import jakarta.inject.Singleton
import jakarta.persistence.EntityManager
import jakarta.transaction.Transactional
import org.slf4j.LoggerFactory
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.LocalTime

/**
 * Service for vulnerability statistics with unified access control
 *
 * Responsibilities:
 * - Provide aggregated vulnerability statistics (most common, severity distribution, etc.)
 * - Apply unified access control (workgroups, domain mappings, AWS account mappings)
 * - Support multiple statistical views: by vulnerability, by severity, by asset, by time
 *
 * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import
 * Task: T004
 * User Stories: US1-US4 (All statistics user stories)
 * Spec reference: spec.md FR-001 through FR-015
 *
 * Access Control: Uses unified access control model via AssetFilterService
 * - ADMIN: Sees all vulnerabilities
 * - Non-admin: Sees vulnerabilities from accessible assets based on:
 *   - Workgroup membership
 *   - Domain mappings (UserMapping.domain matches Asset.adDomain)
 *   - AWS account mappings (UserMapping.awsAccountId matches Asset.cloudAccountId)
 *   - Manual asset creation
 *   - Scan uploads
 */
@Singleton
open class VulnerabilityStatisticsService(
    private val vulnerabilityRepository: VulnerabilityRepository,
    private val assetFilterService: AssetFilterService,
    private val entityManager: EntityManager,
    private val statisticsCacheService: VulnerabilityStatisticsCacheService,
    private val objectMapper: ObjectMapper
) {
    private val log = LoggerFactory.getLogger(VulnerabilityStatisticsService::class.java)

    /**
     * Check if user has universal access role (ADMIN or SECCHAMPION)
     *
     * These users bypass access filtering and see all statistics
     *
     * @param authentication Current user authentication context
     * @return true if user has ADMIN or SECCHAMPION role, false otherwise
     */
    private fun isAdmin(authentication: Authentication): Boolean {
        return authentication.roles.contains("ADMIN") || authentication.roles.contains("SECCHAMPION")
    }

    /**
     * Get asset IDs accessible to the current user using unified access control
     *
     * Uses AssetFilterService to apply unified access control model:
     * - Workgroup membership
     * - Domain mappings (AD domains)
     * - AWS account mappings
     * - Manual asset creation
     * - Scan uploads
     *
     * @param authentication Current user authentication context
     * @return Set of accessible asset IDs, or null if user is ADMIN (sees all)
     */
    private fun getAccessibleAssetIds(authentication: Authentication): Set<Long>? {
        if (isAdmin(authentication)) {
            // ADMIN sees all - return null to indicate no filtering needed
            return null
        }

        // Use AssetFilterService to get accessible assets with unified access control
        val accessibleAssets = assetFilterService.getAccessibleAssets(authentication)
        return accessibleAssets.mapNotNull { it.id }.toSet()
    }

    /**
     * Get available domains for filtering from user's accessible assets
     *
     * Returns list of unique AD domains from assets the user has access to.
     * Used to populate the domain selector dropdown.
     *
     * Feature: 059-vuln-stats-domain-filter
     * Task: T002
     * Spec reference: spec.md FR-002
     *
     * @param authentication Current user authentication context
     * @return AvailableDomainsDto with sorted domain list and asset count
     */
    fun getAvailableDomains(authentication: Authentication): com.secman.dto.AvailableDomainsDto {
        // Use existing access control - getAccessibleAssets handles ADMIN case internally
        val accessibleAssets = assetFilterService.getAccessibleAssets(authentication)

        // Extract unique domains (non-null, normalized to lowercase)
        val domains = accessibleAssets
            .mapNotNull { it.adDomain }
            .filter { it.isNotBlank() }
            .map { it.lowercase() }
            .distinct()
            .sorted()

        // Count assets with domains
        val totalAssetCount = accessibleAssets.count { !it.adDomain.isNullOrBlank() }

        return com.secman.dto.AvailableDomainsDto(
            domains = domains,
            totalAssetCount = totalAssetCount
        )
    }

    /**
     * Get accessible asset IDs with optional domain and AWS hosted filters
     *
     * Applies domain and awsHosted filters on top of existing access control.
     * Filters NEVER bypass RBAC - they are additional constraints.
     *
     * Feature: 059-vuln-stats-domain-filter
     * Task: T002
     *
     * @param authentication Current user authentication context
     * @param domain Optional domain filter (null = all domains)
     * @param awsHosted Optional AWS hosted filter (true = only assets with cloudAccountId)
     * @return Set of accessible asset IDs, or null if user is ADMIN with no filters
     */
    private fun getAccessibleAssetIdsWithDomain(authentication: Authentication, domain: String?, awsHosted: Boolean? = null): Set<Long>? {
        // Get base accessible assets
        val baseAssetIds = getAccessibleAssetIds(authentication)

        // If no filters, return base result
        if (domain.isNullOrBlank() && awsHosted != true) {
            return baseAssetIds
        }

        // Get accessible assets (getAccessibleAssets handles ADMIN case internally)
        val accessibleAssets = assetFilterService.getAccessibleAssets(authentication)

        // Apply filters
        var filtered = accessibleAssets.asSequence()

        // Filter by domain
        if (!domain.isNullOrBlank()) {
            val normalizedDomain = domain.lowercase()
            filtered = filtered.filter { it.adDomain?.lowercase() == normalizedDomain }
        }

        // Filter by AWS hosted (non-blank cloudAccountId)
        if (awsHosted == true) {
            filtered = filtered.filter { !it.cloudAccountId.isNullOrBlank() }
        }

        return filtered.mapNotNull { it.id }.toSet()
    }

    /**
     * Get most common vulnerabilities with unified access control and optional domain filter
     *
     * Returns top 10 vulnerabilities ranked by occurrence frequency across accessible assets.
     * Access control:
     * - ADMIN role: sees all vulnerabilities (no filtering)
     * - Non-admin: sees vulnerabilities from accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import, 059-vuln-stats-domain-filter
     * Task: T013 [US1], T004 (domain filter)
     * Spec reference: spec.md FR-001, FR-002, FR-006
     * User Story: US1 - View Most Common Vulnerabilities (P1)
     *
     * @param authentication Current user authentication context
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return List of most common vulnerabilities (max 10) with occurrence counts
     */
    fun getMostCommonVulnerabilities(authentication: Authentication, domain: String? = null, awsHosted: Boolean? = null): List<com.secman.dto.MostCommonVulnerabilityDto> {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        // Try cache for unfiltered admin/secchampion queries
        if (accessibleAssetIds == null) {
            val cached = statisticsCacheService.getCachedEntry(VulnerabilityStatisticsCacheService.KEY_MOST_COMMON)
            if (cached != null) {
                log.debug("Serving most_common from cache (refreshed: {})", cached.lastRefreshedAt)
                return objectMapper.readValue(cached.cachedJson, object : TypeReference<List<com.secman.dto.MostCommonVulnerabilityDto>>() {})
            }
        }

        val rawResults = if (accessibleAssetIds == null) {
            // ADMIN sees all vulnerabilities (with no domain filter)
            vulnerabilityRepository.findMostCommonVulnerabilitiesForAll()
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets (or no assets in selected domain) - return empty list
            return emptyList()
        } else {
            // User sees vulnerabilities from accessible assets (unified access control + domain filter)
            vulnerabilityRepository.findMostCommonVulnerabilitiesForAssets(accessibleAssetIds)
        }

        // Transform raw results into DTOs
        return rawResults.map { row ->
            com.secman.dto.MostCommonVulnerabilityDto(
                vulnerabilityId = row.vulnerabilityId ?: "",
                cvssSeverity = row.cvssSeverity ?: "UNKNOWN",
                occurrenceCount = row.occurrenceCount?.toLong() ?: 0L,
                affectedAssetCount = row.affectedAssetCount?.toLong() ?: 0L
            )
        }
    }

    /**
     * Get most vulnerable products with unified access control and optional domain filter
     *
     * Returns top 10 products ranked by distinct vulnerability count across accessible assets.
     * Access control:
     * - ADMIN role: sees all vulnerabilities (no filtering)
     * - Non-admin: sees vulnerabilities from accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 059-vuln-stats-domain-filter
     * Task: T005 (domain filter)
     * Spec reference: spec.md
     *
     * @param authentication Current user authentication context
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return List of most vulnerable products (max 10) with vulnerability counts
     */
    fun getMostVulnerableProducts(authentication: Authentication, domain: String? = null, awsHosted: Boolean? = null): List<com.secman.dto.MostVulnerableProductDto> {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        // Try cache for unfiltered admin/secchampion queries
        if (accessibleAssetIds == null) {
            val cached = statisticsCacheService.getCachedEntry(VulnerabilityStatisticsCacheService.KEY_MOST_VULNERABLE_PRODUCTS)
            if (cached != null) {
                log.debug("Serving most_vulnerable_products from cache (refreshed: {})", cached.lastRefreshedAt)
                return objectMapper.readValue(cached.cachedJson, object : TypeReference<List<com.secman.dto.MostVulnerableProductDto>>() {})
            }
        }

        val rawResults = if (accessibleAssetIds == null) {
            // ADMIN sees all vulnerabilities (with no domain filter)
            vulnerabilityRepository.findMostVulnerableProductsForAll()
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets (or no assets in selected domain) - return empty list
            return emptyList()
        } else {
            // User sees vulnerabilities from accessible assets (unified access control + domain filter)
            vulnerabilityRepository.findMostVulnerableProductsForAssets(accessibleAssetIds)
        }

        // Transform raw results into DTOs
        return rawResults.map { row ->
            com.secman.dto.MostVulnerableProductDto(
                product = row.product ?: "",
                vulnerabilityCount = row.vulnerabilityCount?.toLong() ?: 0L,
                affectedAssetCount = row.affectedAssetCount?.toLong() ?: 0L,
                criticalCount = row.criticalCount?.toLong() ?: 0L,
                highCount = row.highCount?.toLong() ?: 0L
            )
        }
    }

    /**
     * Get severity distribution with unified access control and optional domain filter
     *
     * Returns vulnerability counts grouped by CVSS severity level (CRITICAL, HIGH, MEDIUM, LOW, UNKNOWN).
     * Includes computed percentage properties for each severity level.
     * Access control:
     * - ADMIN role: sees all vulnerabilities (no filtering)
     * - Non-admin: sees vulnerabilities from accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import, 059-vuln-stats-domain-filter
     * Task: T023 [US2], T006 (domain filter)
     * Spec reference: spec.md FR-003, FR-004, FR-006
     * User Story: US2 - View Severity Distribution (P2)
     *
     * @param authentication Current user authentication context
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return SeverityDistributionDto with counts and percentages for each severity level
     */
    fun getSeverityDistribution(authentication: Authentication, domain: String? = null, awsHosted: Boolean? = null): com.secman.dto.SeverityDistributionDto {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        // Try cache for unfiltered admin/secchampion queries
        if (accessibleAssetIds == null) {
            val cached = statisticsCacheService.getCachedEntry(VulnerabilityStatisticsCacheService.KEY_SEVERITY_DISTRIBUTION)
            if (cached != null) {
                log.debug("Serving severity_distribution from cache (refreshed: {})", cached.lastRefreshedAt)
                return objectMapper.readValue(cached.cachedJson, com.secman.dto.SeverityDistributionDto::class.java)
            }
        }

        // Get raw severity counts from repository
        val rawResults = if (accessibleAssetIds == null) {
            vulnerabilityRepository.findSeverityDistributionForAll()
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets (or no assets in selected domain) - return empty results
            emptyList()
        } else {
            vulnerabilityRepository.findSeverityDistributionForAssets(accessibleAssetIds)
        }

        // Aggregate results into severity counts
        var criticalCount = 0L
        var highCount = 0L
        var mediumCount = 0L
        var lowCount = 0L
        var unknownCount = 0L

        rawResults.forEach { row ->
            val severity = row.severity ?: "UNKNOWN"
            val count = row.count?.toLong() ?: 0L

            when (severity.uppercase()) {
                "CRITICAL" -> criticalCount = count
                "HIGH" -> highCount = count
                "MEDIUM" -> mediumCount = count
                "LOW" -> lowCount = count
                "UNKNOWN" -> unknownCount = count
            }
        }

        return com.secman.dto.SeverityDistributionDto(
            critical = criticalCount,
            high = highCount,
            medium = mediumCount,
            low = lowCount,
            unknown = unknownCount
        )
    }

    /**
     * Get top assets ranked by vulnerability count with unified access control and optional domain filter
     *
     * Returns top 10 assets ranked by total vulnerability count with severity breakdowns.
     * Access control:
     * - ADMIN role: sees all assets (no filtering)
     * - Non-admin: sees accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import, 059-vuln-stats-domain-filter
     * Task: T033 [US3]
     * Spec reference: spec.md FR-005, FR-006
     * User Story: US3 - View Asset Vulnerability Statistics (P3)
     *
     * @param authentication Current user authentication context
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return List of top 10 assets with vulnerability counts and severity breakdowns
     */
    fun getTopAssetsByVulnerabilities(authentication: Authentication, domain: String? = null, awsHosted: Boolean? = null): List<com.secman.dto.TopAssetByVulnerabilitiesDto> {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        // Try cache for unfiltered admin/secchampion queries
        if (accessibleAssetIds == null) {
            val cached = statisticsCacheService.getCachedEntry(VulnerabilityStatisticsCacheService.KEY_TOP_ASSETS)
            if (cached != null) {
                log.debug("Serving top_assets from cache (refreshed: {})", cached.lastRefreshedAt)
                return objectMapper.readValue(cached.cachedJson, object : TypeReference<List<com.secman.dto.TopAssetByVulnerabilitiesDto>>() {})
            }
        }

        val rawResults = if (accessibleAssetIds == null) {
            // ADMIN sees all assets
            vulnerabilityRepository.findTopAssetsByVulnerabilitiesForAll()
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets - return empty list
            return emptyList()
        } else {
            // Non-admin user sees accessible assets (unified access control)
            vulnerabilityRepository.findTopAssetsByVulnerabilitiesForAssets(accessibleAssetIds)
        }

        // Transform raw results into DTOs
        return rawResults.map { row ->
            com.secman.dto.TopAssetByVulnerabilitiesDto(
                assetId = row.assetId?.toLong() ?: 0L,
                assetName = row.assetName ?: "",
                assetType = row.assetType,
                assetIp = row.assetIp,
                totalVulnerabilityCount = row.totalVulnerabilityCount?.toLong() ?: 0L,
                criticalCount = row.criticalCount?.toLong() ?: 0L,
                highCount = row.highCount?.toLong() ?: 0L,
                mediumCount = row.mediumCount?.toLong() ?: 0L,
                lowCount = row.lowCount?.toLong() ?: 0L
            )
        }
    }

    /**
     * Get vulnerability statistics grouped by asset type with unified access control
     *
     * Returns vulnerability counts aggregated by asset type (Server, Workstation, etc.) with
     * severity breakdowns and average vulnerabilities per asset.
     * Access control:
     * - ADMIN role: sees all asset types (no filtering)
     * - Non-admin: sees asset types from accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import
     * Task: T037 [US3]
     * Spec reference: spec.md FR-007, FR-008
     * User Story: US3 - View Asset Vulnerability Statistics (P3)
     *
     * @param authentication Current user authentication context
     * @return List of asset types with vulnerability statistics
     */
    fun getVulnerabilitiesByAssetType(authentication: Authentication): List<com.secman.dto.VulnerabilityByAssetTypeDto> {
        val accessibleAssetIds = getAccessibleAssetIds(authentication)

        // Get raw results from repository
        val rawResults = if (accessibleAssetIds == null) {
            vulnerabilityRepository.findVulnerabilitiesByAssetTypeForAll()
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets - return empty results
            return emptyList()
        } else {
            vulnerabilityRepository.findVulnerabilitiesByAssetTypeForAssets(accessibleAssetIds)
        }

        // Transform raw results into DTOs
        return rawResults.map { row ->
            com.secman.dto.VulnerabilityByAssetTypeDto(
                assetType = row["assetType"] as? String ?: "Unknown",
                assetCount = (row["assetCount"] as? Number)?.toLong() ?: 0L,
                totalVulnerabilityCount = (row["totalVulnerabilityCount"] as? Number)?.toLong() ?: 0L,
                criticalCount = (row["criticalCount"] as? Number)?.toLong() ?: 0L,
                highCount = (row["highCount"] as? Number)?.toLong() ?: 0L,
                mediumCount = (row["mediumCount"] as? Number)?.toLong() ?: 0L,
                lowCount = (row["lowCount"] as? Number)?.toLong() ?: 0L,
                averageVulnerabilitiesPerAsset = (row["avgVulnsPerAsset"] as? Number)?.toDouble() ?: 0.0
            )
        }
    }

    /**
     * Get temporal vulnerability trends with unified access control
     *
     * Returns time-series data showing vulnerability counts over specified time period (30, 60, or 90 days).
     * Access control:
     * - ADMIN role: sees all vulnerabilities (no filtering)
     * - Non-admin: sees vulnerabilities from accessible assets (workgroups, domains, AWS accounts, etc.)
     *
     * Feature: 036-vuln-stats-lense, 043-crowdstrike-domain-import
     * Task: T049 [US4]
     * Spec reference: spec.md FR-009, FR-010, FR-011
     * User Story: US4 - View Temporal Trends (P4)
     *
     * @param authentication Current user authentication context
     * @param days Number of days to analyze (30, 60, or 90)
     * @return TemporalTrendsDto with daily data points
     * @throws IllegalArgumentException if days is not 30, 60, or 90
     */
    fun getTemporalTrends(authentication: Authentication, days: Int): com.secman.dto.TemporalTrendsDto {
        // Validate days parameter
        if (days !in listOf(30, 60, 90)) {
            throw IllegalArgumentException("Days parameter must be 30, 60, or 90")
        }

        // Calculate date range
        val endDate = LocalDate.now()
        val startDate = endDate.minusDays(days.toLong())
        val startDateTime = LocalDateTime.of(startDate, LocalTime.MIN)

        val accessibleAssetIds = getAccessibleAssetIds(authentication)

        // Get raw results from repository
        val rawResults = if (accessibleAssetIds == null) {
            vulnerabilityRepository.findTemporalTrendsForAll(startDateTime)
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets - return empty results
            emptyList()
        } else {
            vulnerabilityRepository.findTemporalTrendsForAssets(accessibleAssetIds, startDateTime)
        }

        // Transform raw results into data points
        val dataPoints = rawResults.map { row ->
            com.secman.dto.TemporalTrendDataPointDto(
                date = (row["date"] as java.sql.Date).toLocalDate(),
                totalCount = (row["totalCount"] as? Number)?.toLong() ?: 0L,
                criticalCount = (row["criticalCount"] as? Number)?.toLong() ?: 0L,
                highCount = (row["highCount"] as? Number)?.toLong() ?: 0L,
                mediumCount = (row["mediumCount"] as? Number)?.toLong() ?: 0L,
                lowCount = (row["lowCount"] as? Number)?.toLong() ?: 0L
            )
        }

        return com.secman.dto.TemporalTrendsDto(
            startDate = startDate,
            endDate = endDate,
            days = days,
            dataPoints = dataPoints
        )
    }

    /**
     * Get affected assets for a specific CVE with access control and optional domain filter
     *
     * Returns list of assets affected by the specified CVE, filtered by:
     * - User's access control (workgroups, domain mappings, AWS accounts, etc.)
     * - Optional domain filter
     *
     * @param authentication Current user authentication context
     * @param cveId The CVE identifier (e.g., "CVE-2024-12345")
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return AffectedAssetsByCveDto with list of affected assets (max 100)
     */
    @Transactional
    open fun getAffectedAssetsByCve(
        authentication: Authentication,
        cveId: String,
        domain: String? = null,
        awsHosted: Boolean? = null
    ): com.secman.dto.AffectedAssetsByCveDto {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        val rawResults: List<Array<Any?>> = if (accessibleAssetIds == null) {
            // ADMIN sees all assets (with no domain filter)
            @Suppress("UNCHECKED_CAST")
            entityManager.createNativeQuery(
                """
                SELECT DISTINCT
                    a.id,
                    a.name,
                    a.ip,
                    a.ad_domain,
                    a.cloud_instance_id,
                    a.type
                FROM vulnerability v
                JOIN asset a ON v.asset_id = a.id
                WHERE v.vulnerability_id = :cveId
                AND NOT EXISTS (
                    SELECT 1 FROM vulnerability_exception e WHERE ${ExceptionMatchSql.EXCEPTION_MATCH}
                )
                ORDER BY a.name
                LIMIT 100
                """
            ).setParameter("cveId", cveId).resultList as List<Array<Any?>>
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets - return empty list
            emptyList()
        } else {
            // User sees assets within their access scope + domain filter
            @Suppress("UNCHECKED_CAST")
            entityManager.createNativeQuery(
                """
                SELECT DISTINCT
                    a.id,
                    a.name,
                    a.ip,
                    a.ad_domain,
                    a.cloud_instance_id,
                    a.type
                FROM vulnerability v
                JOIN asset a ON v.asset_id = a.id
                WHERE v.vulnerability_id = :cveId
                AND a.id IN :assetIds
                AND NOT EXISTS (
                    SELECT 1 FROM vulnerability_exception e WHERE ${ExceptionMatchSql.EXCEPTION_MATCH}
                )
                ORDER BY a.name
                LIMIT 100
                """
            ).setParameter("cveId", cveId)
             .setParameter("assetIds", accessibleAssetIds)
             .resultList as List<Array<Any?>>
        }

        // Get severity for this CVE using EntityManager
        val severity = try {
            entityManager.createQuery(
                "SELECT DISTINCT v.cvssSeverity FROM Vulnerability v WHERE v.vulnerabilityId = :cveId",
                String::class.java
            ).setParameter("cveId", cveId)
             .resultList
             .firstOrNull() ?: "UNKNOWN"
        } catch (_: Exception) {
            "UNKNOWN"
        }

        // Transform raw results into DTOs
        // Array indices: [0]=assetId, [1]=assetName, [2]=assetIp, [3]=adDomain, [4]=cloudInstanceId, [5]=assetType
        val affectedAssets = rawResults.map { row ->
            com.secman.dto.AffectedAssetDto(
                assetId = (row[0] as Number).toLong(),
                assetName = row[1] as? String ?: "",
                assetIp = row[2] as? String,
                adDomain = row[3] as? String,
                cloudInstanceId = row[4] as? String,
                assetType = row[5] as? String
            )
        }

        return com.secman.dto.AffectedAssetsByCveDto(
            cveId = cveId,
            severity = severity,
            affectedAssets = affectedAssets,
            totalCount = affectedAssets.size
        )
    }

    /**
     * Get assets that have a specific product installed with access control and optional domain filter
     *
     * Returns list of assets with the specified product, filtered by:
     * - User's access control (workgroups, domain mappings, AWS accounts, etc.)
     * - Optional domain filter
     *
     * @param authentication Current user authentication context
     * @param product The product name to search for
     * @param domain Optional AD domain filter (null = all domains). Case-insensitive.
     * @return AssetsByProductDto with list of assets (max 100)
     */
    @Transactional
    open fun getAssetsByProduct(
        authentication: Authentication,
        product: String,
        domain: String? = null,
        awsHosted: Boolean? = null
    ): com.secman.dto.AssetsByProductDto {
        val accessibleAssetIds = getAccessibleAssetIdsWithDomain(authentication, domain, awsHosted)

        val rawResults: List<Array<Any?>> = if (accessibleAssetIds == null) {
            // ADMIN sees all assets (with no domain filter)
            @Suppress("UNCHECKED_CAST")
            entityManager.createNativeQuery(
                """
                SELECT
                    a.id,
                    a.name,
                    a.ip,
                    a.ad_domain,
                    a.cloud_instance_id,
                    a.type,
                    COUNT(DISTINCT v.id) as vuln_count
                FROM asset a
                JOIN vulnerability v ON v.asset_id = a.id
                WHERE v.vulnerable_product_versions = :product
                AND NOT EXISTS (
                    SELECT 1 FROM vulnerability_exception e WHERE ${ExceptionMatchSql.EXCEPTION_MATCH}
                )
                GROUP BY a.id, a.name, a.ip, a.ad_domain, a.cloud_instance_id, a.type
                ORDER BY vuln_count DESC, a.name
                LIMIT 100
                """
            ).setParameter("product", product).resultList as List<Array<Any?>>
        } else if (accessibleAssetIds.isEmpty()) {
            // User has no accessible assets - return empty list
            emptyList()
        } else {
            // User sees assets within their access scope + domain filter
            @Suppress("UNCHECKED_CAST")
            entityManager.createNativeQuery(
                """
                SELECT
                    a.id,
                    a.name,
                    a.ip,
                    a.ad_domain,
                    a.cloud_instance_id,
                    a.type,
                    COUNT(DISTINCT v.id) as vuln_count
                FROM asset a
                JOIN vulnerability v ON v.asset_id = a.id
                WHERE v.vulnerable_product_versions = :product
                AND a.id IN :assetIds
                AND NOT EXISTS (
                    SELECT 1 FROM vulnerability_exception e WHERE ${ExceptionMatchSql.EXCEPTION_MATCH}
                )
                GROUP BY a.id, a.name, a.ip, a.ad_domain, a.cloud_instance_id, a.type
                ORDER BY vuln_count DESC, a.name
                LIMIT 100
                """
            ).setParameter("product", product)
             .setParameter("assetIds", accessibleAssetIds)
             .resultList as List<Array<Any?>>
        }

        // Transform raw results into DTOs
        // Array indices: [0]=assetId, [1]=assetName, [2]=assetIp, [3]=adDomain, [4]=cloudInstanceId, [5]=assetType, [6]=vulnCount
        val assets = rawResults.map { row ->
            com.secman.dto.AssetWithProductDto(
                assetId = (row[0] as Number).toLong(),
                assetName = row[1] as? String ?: "",
                assetIp = row[2] as? String,
                adDomain = row[3] as? String,
                cloudInstanceId = row[4] as? String,
                assetType = row[5] as? String,
                vulnerabilityCount = (row[6] as Number).toLong()
            )
        }

        return com.secman.dto.AssetsByProductDto(
            product = product,
            assets = assets,
            totalCount = assets.size
        )
    }
}

