package com.secman.repository

import com.secman.domain.WorkgroupAwsAccount
import io.micronaut.data.annotation.Query
import io.micronaut.data.annotation.Repository
import io.micronaut.data.jpa.repository.JpaRepository
import java.util.Optional

@Repository
interface WorkgroupAwsAccountRepository : JpaRepository<WorkgroupAwsAccount, Long> {

    @Query("SELECT DISTINCT waa.awsAccountId FROM WorkgroupAwsAccount waa WHERE EXISTS (SELECT 1 FROM waa.workgroup w JOIN w.users u WHERE u.id = :userId)")
    fun findDistinctAwsAccountIdsByUserId(userId: Long): List<String>

    @Query("SELECT waa FROM WorkgroupAwsAccount waa JOIN FETCH waa.createdBy JOIN FETCH waa.workgroup WHERE waa.workgroup.id = :workgroupId")
    fun findByWorkgroupId(workgroupId: Long): List<WorkgroupAwsAccount>

    fun findByWorkgroupIdAndAwsAccountId(
        workgroupId: Long,
        awsAccountId: String
    ): Optional<WorkgroupAwsAccount>

    fun existsByWorkgroupIdAndAwsAccountId(
        workgroupId: Long,
        awsAccountId: String
    ): Boolean

    fun deleteByWorkgroupId(workgroupId: Long): Long

    fun countByWorkgroupId(workgroupId: Long): Long
}

package com.secman.domain

import com.fasterxml.jackson.annotation.JsonIgnore
import io.micronaut.serde.annotation.Serdeable
import org.hibernate.annotations.JdbcTypeCode
import org.hibernate.type.SqlTypes
import jakarta.persistence.*
import jakarta.validation.constraints.Email
import jakarta.validation.constraints.NotBlank
import java.time.Instant

@Entity
@Table(
    name = "users",
    indexes = [
        // Query optimization indexes (Feature: Database Structure Optimization)
        Index(name = "idx_user_email", columnList = "email"),      // Email lookups for OAuth/mappings
        Index(name = "idx_user_username", columnList = "username") // Username lookups
    ]
)
@Serdeable
data class User(
    @Id
    @GeneratedValue
    var id: Long? = null,

    @Column(unique = true, nullable = false)
    @NotBlank
    var username: String,

    @Column(unique = true, nullable = false)
    @Email
    @NotBlank
    var email: String,

    @Column(name = "password_hash", nullable = false)
    @JsonIgnore
    @NotBlank
    var passwordHash: String,

    @ElementCollection(fetch = FetchType.EAGER)
    @CollectionTable(name = "user_roles", joinColumns = [JoinColumn(name = "user_id")])
    @JdbcTypeCode(SqlTypes.VARCHAR)
    @Enumerated(EnumType.STRING)
    @Column(name = "role_name")
    var roles: MutableSet<Role> = mutableSetOf(Role.USER),

    /**
     * Many-to-many relationship with Workgroup
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     * Feature: 073-memory-optimization (LAZY loading)
     * Users can belong to 0..n workgroups
     *
     * LAZY fetch: Workgroups loaded on-demand to reduce memory for list operations.
     * Use UserRepository.findByIdWithWorkgroups() when workgroups are needed.
     * Feature flag MEMORY_LAZY_LOADING controls service-level behavior.
     *
     * @JsonIgnore prevents LazyInitializationException during JSON serialization.
     * Workgroups should be accessed via service layer, not directly from API responses.
     */
    @JsonIgnore
    @ManyToMany(fetch = FetchType.LAZY)
    @JoinTable(
        name = "user_workgroups",
        joinColumns = [JoinColumn(name = "user_id")],
        inverseJoinColumns = [JoinColumn(name = "workgroup_id")]
    )
    var workgroups: MutableSet<Workgroup> = mutableSetOf(),

    @Column(name = "mfa_enabled", nullable = false, columnDefinition = "BOOLEAN DEFAULT FALSE")
    var mfaEnabled: Boolean = false,

    /**
     * Authentication source tracking
     * Feature: 051-user-password-change
     * Determines if user can change password via self-service
     */
    @Column(name = "auth_source", nullable = false, length = 20)
    @JdbcTypeCode(SqlTypes.VARCHAR)
    @Enumerated(EnumType.STRING)

package com.secman.service

import com.fasterxml.jackson.databind.ObjectMapper
import com.secman.config.VulnerabilityStatisticsCacheConfig
import com.secman.domain.VulnerabilityStatisticsCache
import com.secman.repository.VulnerabilityStatisticsCacheRepository
import com.secman.repository.VulnerabilityRepository
import jakarta.inject.Singleton
import jakarta.transaction.Transactional
import org.slf4j.LoggerFactory
import java.time.LocalDateTime

/**
 * Service for managing pre-computed vulnerability statistics cache
 *
 * Responsibilities:
 * - Refresh cache by running the 4 "ForAll" repository queries, transforming to DTOs, serializing to JSON
 * - Serve cached entries for "All Domains" admin views
 * - Respect feature flag (secman.statistics-cache.enabled)
 *
 * Cache keys:
 * - most_common → List<MostCommonVulnerabilityDto>
 * - most_vulnerable_products → List<MostVulnerableProductDto>
 * - severity_distribution → SeverityDistributionDto
 * - top_assets → List<TopAssetByVulnerabilitiesDto>
 */
@Singleton
open class VulnerabilityStatisticsCacheService(
    private val cacheRepository: VulnerabilityStatisticsCacheRepository,
    private val vulnerabilityRepository: VulnerabilityRepository,
    private val cacheConfig: VulnerabilityStatisticsCacheConfig,
    private val objectMapper: ObjectMapper
) {
    private val log = LoggerFactory.getLogger(VulnerabilityStatisticsCacheService::class.java)

    companion object {
        const val KEY_MOST_COMMON = "most_common"
        const val KEY_MOST_VULNERABLE_PRODUCTS = "most_vulnerable_products"
        const val KEY_SEVERITY_DISTRIBUTION = "severity_distribution"
        const val KEY_TOP_ASSETS = "top_assets"
    }

    fun isCacheEnabled(): Boolean = cacheConfig.enabled

    /**
     * Refresh all 4 statistics cache entries
     *
     * Runs the same repository queries and DTO transformations as VulnerabilityStatisticsService,
     * serializes results to JSON, and upserts into the cache table.
     *
     * Called at the end of MaterializedViewRefreshService.executeRefresh().
     */
    open fun refreshCache() {
        if (!cacheConfig.enabled) {
            log.info("Statistics cache is disabled, skipping refresh")
            return
        }

        log.info("Starting vulnerability statistics cache refresh")
        val overallStart = System.currentTimeMillis()

        try {
            refreshMostCommon()
            refreshMostVulnerableProducts()
            refreshSeverityDistribution()
            refreshTopAssets()

            val totalDuration = System.currentTimeMillis() - overallStart
            log.info("Statistics cache refresh completed in {}ms", totalDuration)
        } catch (e: Exception) {
            log.error("Statistics cache refresh failed: {}", e.message, e)
        }
    }

    /**
     * Get a cached entry by key, or null if cache is disabled or entry doesn't exist
     */
    fun getCachedEntry(cacheKey: String): VulnerabilityStatisticsCache? {
        if (!cacheConfig.enabled) return null
        return cacheRepository.findByCacheKey(cacheKey).orElse(null)
    }

    /**
     * Get the most recent lastRefreshedAt across all cache entries
     */
    fun getLastRefreshedAt(): LocalDateTime? {
        if (!cacheConfig.enabled) return null
        return listOf(KEY_MOST_COMMON, KEY_MOST_VULNERABLE_PRODUCTS, KEY_SEVERITY_DISTRIBUTION, KEY_TOP_ASSETS)
            .mapNotNull { cacheRepository.findByCacheKey(it).orElse(null)?.lastRefreshedAt }
            .maxOrNull()
    }

    private fun refreshMostCommon() {
        val start = System.currentTimeMillis()
        val rawResults = vulnerabilityRepository.findMostCommonVulnerabilitiesForAll()
        val dtos = rawResults.map { row ->
            com.secman.dto.MostCommonVulnerabilityDto(
                vulnerabilityId = row.vulnerabilityId ?: "",
                cvssSeverity = row.cvssSeverity ?: "UNKNOWN",
                occurrenceCount = row.occurrenceCount?.toLong() ?: 0L,
                affectedAssetCount = row.affectedAssetCount?.toLong() ?: 0L
            )
        }
        val json = objectMapper.writeValueAsString(dtos)
        upsertCache(KEY_MOST_COMMON, json, System.currentTimeMillis() - start)
        log.debug("Refreshed cache key '{}': {} entries", KEY_MOST_COMMON, dtos.size)
    }

    private fun refreshMostVulnerableProducts() {
        val start = System.currentTimeMillis()
        val rawResults = vulnerabilityRepository.findMostVulnerableProductsForAll()
        val dtos = rawResults.map { row ->
            com.secman.dto.MostVulnerableProductDto(
                product = row.product ?: "",
                vulnerabilityCount = row.vulnerabilityCount?.toLong() ?: 0L,
                affectedAssetCount = row.affectedAssetCount?.toLong() ?: 0L,
                criticalCount = row.criticalCount?.toLong() ?: 0L,
                highCount = row.highCount?.toLong() ?: 0L
            )
        }
        val json = objectMapper.writeValueAsString(dtos)
        upsertCache(KEY_MOST_VULNERABLE_PRODUCTS, json, System.currentTimeMillis() - start)
        log.debug("Refreshed cache key '{}': {} entries", KEY_MOST_VULNERABLE_PRODUCTS, dtos.size)
    }

    private fun refreshSeverityDistribution() {
        val start = System.currentTimeMillis()
        val rawResults = vulnerabilityRepository.findSeverityDistributionForAll()

        var criticalCount = 0L
        var highCount = 0L
        var mediumCount = 0L
        var lowCount = 0L
        var unknownCount = 0L

        rawResults.forEach { row ->
            val severity = row.severity ?: "UNKNOWN"
            val count = row.count?.toLong() ?: 0L
            when (severity.uppercase()) {
                "CRITICAL" -> criticalCount = count
                "HIGH" -> highCount = count
                "MEDIUM" -> mediumCount = count
                "LOW" -> lowCount = count
                "UNKNOWN" -> unknownCount = count
            }
        }

        val dto = com.secman.dto.SeverityDistributionDto(
            critical = criticalCount,
            high = highCount,
            medium = mediumCount,
            low = lowCount,
            unknown = unknownCount
        )
        val json = objectMapper.writeValueAsString(dto)
        upsertCache(KEY_SEVERITY_DISTRIBUTION, json, System.currentTimeMillis() - start)
        log.debug("Refreshed cache key '{}'", KEY_SEVERITY_DISTRIBUTION)
    }

    private fun refreshTopAssets() {
        val start = System.currentTimeMillis()
        val rawResults = vulnerabilityRepository.findTopAssetsByVulnerabilitiesForAll()
        val dtos = rawResults.map { row ->
            com.secman.dto.TopAssetByVulnerabilitiesDto(
                assetId = row.assetId?.toLong() ?: 0L,
                assetName = row.assetName ?: "",
                assetType = row.assetType,
                assetIp = row.assetIp,
                totalVulnerabilityCount = row.totalVulnerabilityCount?.toLong() ?: 0L,
                criticalCount = row.criticalCount?.toLong() ?: 0L,
                highCount = row.highCount?.toLong() ?: 0L,
                mediumCount = row.mediumCount?.toLong() ?: 0L,
                lowCount = row.lowCount?.toLong() ?: 0L
            )
        }
        val json = objectMapper.writeValueAsString(dtos)
        upsertCache(KEY_TOP_ASSETS, json, System.currentTimeMillis() - start)
        log.debug("Refreshed cache key '{}': {} entries", KEY_TOP_ASSETS, dtos.size)
    }

    @Transactional
    open fun upsertCache(cacheKey: String, json: String, durationMs: Long) {
        val existing = cacheRepository.findByCacheKey(cacheKey)
        if (existing.isPresent) {
            val entry = existing.get()
            entry.cachedJson = json
            entry.lastRefreshedAt = LocalDateTime.now()
            entry.refreshDurationMs = durationMs
            cacheRepository.update(entry)
        } else {
            cacheRepository.save(
                VulnerabilityStatisticsCache(
                    cacheKey = cacheKey,
                    cachedJson = json,
                    lastRefreshedAt = LocalDateTime.now(),
                    refreshDurationMs = durationMs
                )
            )
        }
    }
}

